<?php/DevelopmentErrorReportingif(!defined('DEVELOPMENT_MODE')){error_reporting(E_ALL);ini_set('display_errors',1);ini_set('display_startup_errors',1);}declare(strict_types=1);/***DataIntegrityValidator*Comprehensivedatavalidationandconsistencychecks*/require_once__DIR__.'/../core/config.php';require_once__DIR__.'/../core/Database.php';classDataIntegrityValidator{private$pdo;private$issues=[];publicfunction__construct(){$db=Database::getInstance();$this->pdo=$db->getConnection();}/***Validatealldataintegrity*/publicfunctionvalidateAll(){$this->issues=[];$this->validatePersonilIntegrity();$this->validateUnsurIntegrity();$this->validateBagianIntegrity();$this->validateJabatanIntegrity();$this->validateRelationships();$this->validateDataConsistency();$this->validateBusinessRules();return$this->generateReport();}/***Validatepersonildataintegrity*/privatefunctionvalidatePersonilIntegrity(){/Checkformissingrequiredfields$stmt=$this->pdo->query("SELECTid,nama,nrpFROMpersonilWHEREis_deleted=0AND(namaISnullORnama=''ORnrpISnullORnrp='')");$missing_required=$stmt->fetchAll();forforeach($missing_requiredas$person){$this->issues[]=['type'=>'missing_required_fields','table'=>'personil','record_id'=>$person['id'],'description'=>"PersonilID{$person['id']}missingrequiredfields(namaornrp)",'severity'=>'high'];}/CheckforduplicateNRP$stmt=$this->pdo->query("SELECTnrp,COUNT(*)ascount,GROUP_CONCAT(id)asidsFROMpersonilWHEREis_deleted=0ANDnrpISNOTnullANDnrp!=''GROUPBYnrpHAVINGcount>1");$duplicate_nrps=$stmt->fetchAll();forforeach($duplicate_nrpsas$dup){$this->issues[]=['type'=>'duplicate_nrp','table'=>'personil','description'=>"DuplicateNRP'{$dup['nrp']}'foundinrecords:{$dup['ids']}",'severity'=>'high','count'=>$dup['count']];}/Checkforinvaliddates$stmt=$this->pdo->query("SELECTid,nama,tanggal_lahir,tanggal_masuk,tanggal_pensiunFROMpersonilWHEREis_deleted=0AND((tanggal_lahirISNOTnullANDtanggal_lahir!=''AND(tanggal_lahir>CURDATE()ORtanggal_lahir<'1900-01-01'))OR(tanggal_masukISNOTnullANDtanggal_masuk!=''AND(tanggal_masuk>CURDATE()ORtanggal_masuk<'1950-01-01'))OR(tanggal_pensiunISNOTnullANDtanggal_pensiun!=''AND(tanggal_pensiun>CURDATE()ORtanggal_pensiun<'1950-01-01')))");$invalid_dates=$stmt->fetchAll();forforeach($invalid_datesas$person){$this->issues[]=['type'=>'invalid_date','table'=>'personil','record_id'=>$person['id'],'description'=>"PersonilID{$person['id']}hasinvaliddates",'severity'=>'medium','details'=>$person];}/Checklogicaldateconsistency$stmt=$this->pdo->query("SELECTid,nama,tanggal_lahir,tanggal_masuk,tanggal_pensiunFROMpersonilWHEREis_deleted=0AND((tanggal_lahirISNOTnullANDtanggal_masukISNOTnullANDtanggal_lahir>tanggal_masuk)OR(tanggal_masukISNOTnullANDtanggal_pensiunISNOTnullANDtanggal_masuk>tanggal_pensiun)OR(tanggal_lahirISNOTnullANDtanggal_pensiunISNOTnullANDtanggal_lahir>tanggal_pensiun))");$inconsistent_dates=$stmt->fetchAll();forforeach($inconsistent_datesas$person){$this->issues[]=['type'=>'inconsistent_dates','table'=>'personil','record_id'=>$person['id'],'description'=>"PersonilID{$person['id']}hasinconsistentdatelogic",'severity'=>'medium','details'=>$person];}}/***Validateunsurdataintegrity*/privatefunctionvalidateUnsurIntegrity(){/Checkformissingrequiredfields$stmt=$this->pdo->query("SELECTid,nama_unsur,kode_unsurFROMunsurWHEREnama_unsurISnullORnama_unsur=''ORkode_unsurISnullORkode_unsur=''");$missing_required=$stmt->fetchAll();forforeach($missing_requiredas$unsur){$this->issues[]=['type'=>'missing_required_fields','table'=>'unsur','record_id'=>$unsur['id'],'description'=>"UnsurID{$unsur['id']}missingrequiredfields",'severity'=>'high'];}/Checkforduplicatekode_unsur$stmt=$this->pdo->query("SELECTkode_unsur,COUNT(*)ascount,GROUP_CONCAT(id)asidsFROMunsurGROUPBYkode_unsurHAVINGcount>1");$duplicate_kodes=$stmt->fetchAll();forforeach($duplicate_kodesas$dup){$this->issues[]=['type'=>'duplicate_kode_unsur','table'=>'unsur','description'=>"Duplicatekode_unsur'{$dup['kode_unsur']}'foundinrecords:{$dup['ids']}",'severity'=>'high','count'=>$dup['count']];}/Checkforduplicateurutan$stmt=$this->pdo->query("SELECTurutan,COUNT(*)ascount,GROUP_CONCAT(id)asidsFROMunsurGROUPBYurutanHAVINGcount>1");$duplicate_urutan=$stmt->fetchAll();forforeach($duplicate_urutanas$dup){$this->issues[]=['type'=>'duplicate_urutan','table'=>'unsur','description'=>"Duplicateurutan'{$dup['urutan']}'foundinrecords:{$dup['ids']}",'severity'=>'medium','count'=>$dup['count']];}}/***Validatebagiandataintegrity*/privatefunctionvalidateBagianIntegrity(){/Checkformissingrequiredfields$stmt=$this->pdo->query("SELECTid,nama_bagian,id_unsurFROMbagianWHEREnama_bagianISnullORnama_bagian=''ORid_unsurISnullORid_unsur=0");$missing_required=$stmt->fetchAll();forforeach($missing_requiredas$bagian){$this->issues[]=['type'=>'missing_required_fields','table'=>'bagian','record_id'=>$bagian['id'],'description'=>"BagianID{$bagian['id']}missingrequiredfields",'severity'=>'high'];}/Checkforduplicatenama_bagianwithinsameunsur$stmt=$this->pdo->query("SELECTid_unsur,nama_bagian,COUNT(*)ascount,GROUP_CONCAT(id)asidsFROMbagianGROUPBYid_unsur,nama_bagianHAVINGcount>1");$duplicate_names=$stmt->fetchAll();forforeach($duplicate_namesas$dup){$this->issues[]=['type'=>'duplicate_bagian_name','table'=>'bagian','description'=>"Duplicatebagianname'{$dup['nama_bagian']}'inunsur{$dup['id_unsur']}foundinrecords:{$dup['ids']}",'severity'=>'medium','count'=>$dup['count']];}/Checkforduplicateurutanwithinsameunsur$stmt=$this->pdo->query("SELECTid_unsur,urutan,COUNT(*)ascount,GROUP_CONCAT(id)asidsFROMbagianGROUPBYid_unsur,urutanHAVINGcount>1");$duplicate_urutan=$stmt->fetchAll();forforeach($duplicate_urutanas$dup){$this->issues[]=['type'=>'duplicate_bagian_urutan','table'=>'bagian','description'=>"Duplicateurutan'{$dup['urutan']}'inunsur{$dup['id_unsur']}foundinrecords:{$dup['ids']}",'severity'=>'medium','count'=>$dup['count']];}}/***Validatejabatandataintegrity*/privatefunctionvalidateJabatanIntegrity(){/Checkformissingrequiredfields$stmt=$this->pdo->query("SELECTid,nama_jabatan,id_unsurFROMjabatanWHEREnama_jabatanISnullORnama_jabatan=''ORid_unsurISnullORid_unsur=0");$missing_required=$stmt->fetchAll();forforeach($missing_requiredas$jabatan){$this->issues[]=['type'=>'missing_required_fields','table'=>'jabatan','record_id'=>$jabatan['id'],'description'=>"JabatanID{$jabatan['id']}missingrequiredfields",'severity'=>'high'];}/Checkforduplicatenama_jabatanwithinsameunsur$stmt=$this->pdo->query("SELECTid_unsur,nama_jabatan,COUNT(*)ascount,GROUP_CONCAT(id)asidsFROMjabatanGROUPBYid_unsur,nama_jabatanHAVINGcount>1");$duplicate_names=$stmt->fetchAll();forforeach($duplicate_namesas$dup){$this->issues[]=['type'=>'duplicate_jabatan_name','table'=>'jabatan','description'=>"Duplicatejabatanname'{$dup['nama_jabatan']}'inunsur{$dup['id_unsur']}foundinrecords:{$dup['ids']}",'severity'=>'medium','count'=>$dup['count']];}}/***Validaterelationshipsbetweentables*/privatefunctionvalidateRelationships(){/Checkpersonilwithinvalidunsurreferences$stmt=$this->pdo->query("SELECTp.id,p.nama,p.id_unsurFROMpersonilpWHEREp.is_deleted=0ANDp.id_unsur>0ANDNOTEXISTS(SELECT1FROMunsuruWHEREu.id=p.id_unsur)");$invalid_unsur_refs=$stmt->fetchAll();forforeach($invalid_unsur_refsas$person){$this->issues[]=['type'=>'invalid_unsur_reference','table'=>'personil','record_id'=>$person['id'],'description'=>"PersonilID{$person['id']}referencesnon-existentunsurID{$person['id_unsur']}",'severity'=>'high'];}/Checkpersonilwithinvalidbagianreferences$stmt=$this->pdo->query("SELECTp.id,p.nama,p.id_bagianFROMpersonilpWHEREp.is_deleted=0ANDp.id_bagian>0ANDNOTEXISTS(SELECT1FROMbagianbWHEREb.id=p.id_bagian)");$invalid_bagian_refs=$stmt->fetchAll();forforeach($invalid_bagian_refsas$person){$this->issues[]=['type'=>'invalid_bagian_reference','table'=>'personil','record_id'=>$person['id'],'description'=>"PersonilID{$person['id']}referencesnon-existentbagianID{$person['id_bagian']}",'severity'=>'high'];}/Checkpersonilwithinvalidjabatanreferences$stmt=$this->pdo->query("SELECTp.id,p.nama,p.id_jabatanFROMpersonilpWHEREp.is_deleted=0ANDp.id_jabatan>0ANDNOTEXISTS(SELECT1FROMjabatanjWHEREj.id=p.id_jabatan)");$invalid_jabatan_refs=$stmt->fetchAll();forforeach($invalid_jabatan_refsas$person){$this->issues[]=['type'=>'invalid_jabatan_reference','table'=>'personil','record_id'=>$person['id'],'description'=>"PersonilID{$person['id']}referencesnon-existentjabatanID{$person['id_jabatan']}",'severity'=>'high'];}/Checkbagianwithinvalidunsurreferences$stmt=$this->pdo->query("SELECTb.id,b.nama_bagian,b.id_unsurFROMbagianbWHEREb.id_unsur>0ANDNOTEXISTS(SELECT1FROMunsuruWHEREu.id=b.id_unsur)");$invalid_bagian_unsur=$stmt->fetchAll();forforeach($invalid_bagian_unsuras$bagian){$this->issues[]=['type'=>'invalid_unsur_reference','table'=>'bagian','record_id'=>$bagian['id'],'description'=>"BagianID{$bagian['id']}referencesnon-existentunsurID{$bagian['id_unsur']}",'severity'=>'high'];}/Checkjabatanwithinvalidunsurreferences$stmt=$this->pdo->query("SELECTj.id,j.nama_jabatan,j.id_unsurFROMjabatanjWHEREj.id_unsur>0ANDNOTEXISTS(SELECT1FROMunsuruWHEREu.id=j.id_unsur)");$invalid_jabatan_unsur=$stmt->fetchAll();forforeach($invalid_jabatan_unsuras$jabatan){$this->issues[]=['type'=>'invalid_unsur_reference','table'=>'jabatan','record_id'=>$jabatan['id'],'description'=>"JabatanID{$jabatan['id']}referencesnon-existentunsurID{$jabatan['id_unsur']}",'severity'=>'high'];}}/***Validatedataconsistency*/privatefunctionvalidateDataConsistency(){/Checkforpersonilwithstatus'nonaktif'butnoalasan_status$stmt=$this->pdo->query("SELECTid,nama,status_ketFROMpersonilWHEREis_deleted=0ANDstatus_ket='nonaktif'AND(alasan_statusISnullORalasan_status='')");$missing_alasan=$stmt->fetchAll();forforeach($missing_alasanas$person){$this->issues[]=['type'=>'missing_alasan_status','table'=>'personil','record_id'=>$person['id'],'description'=>"PersonilID{$person['id']}hasstatus'nonaktif'butmissingalasan_status",'severity'=>'medium'];}/Checkforpersonilwithstatus'aktif'buthasalasan_status$stmt=$this->pdo->query("SELECTid,nama,status_ketFROMpersonilWHEREis_deleted=0ANDstatus_ket='aktif'ANDalasan_statusISNOTnullANDalasan_status!=''");$inconsistent_status=$stmt->fetchAll();forforeach($inconsistent_statusas$person){$this->issues[]=['type'=>'inconsistent_status','table'=>'personil','record_id'=>$person['id'],'description'=>"PersonilID{$person['id']}hasstatus'aktif'buthasalasan_status",'severity'=>'low'];}}/***Validatebusinessrules*/privatefunctionvalidateBusinessRules(){/Checkifthereareanypersonilwithoutassignedunsur$stmt=$this->pdo->query("SELECTCOUNT(*)ascountFROMpersonilWHEREis_deleted=0AND(id_unsurISnullORid_unsur=0)");$no_unsur=$stmt->fetch()['count'];if($no_unsur>0){$this->issues[]=['type'=>'business_rule_violation','table'=>'personil','description'=>"Found{$no_unsur}personilwithoutassignedunsur",'severity'=>'medium','count'=>$no_unsur];}/Checkifthereareanybagianwithoutassignedunsur$stmt=$this->pdo->query("SELECTCOUNT(*)ascountFROMbagianWHEREid_unsurISnullORid_unsur=0");$no_unsur=$stmt->fetch()['count'];if($no_unsur>0){$this->issues[]=['type'=>'business_rule_violation','table'=>'bagian','description'=>"Found{$no_unsur}bagianwithoutassignedunsur",'severity'=>'high','count'=>$no_unsur];}/Checkifthereareanyjabatanwithoutassignedunsur$stmt=$this->pdo->query("SELECTCOUNT(*)ascountFROMjabatanWHEREid_unsurISnullORid_unsur=0");$no_unsur=$stmt->fetch()['count'];if($no_unsur>0){$this->issues[]=['type'=>'business_rule_violation','table'=>'jabatan','description'=>"Found{$no_unsur}jabatanwithoutassignedunsur",'severity'=>'high','count'=>$no_unsur];}}/***Generatevalidationreport*/privatefunctiongenerateReport(){$total_issues=count($this->issues);$severity_counts=['high'=>0,'medium'=>0,'low'=>0];$type_counts=[];$table_counts=[];forforeach($this->issuesas$issue){$severity=$issue['severity']??'medium';$type=$issue['type']??'unknown';$table=$issue['table']??'unknown';$severity_counts[$severity]++;$type_counts[$type]=($type_counts[$type]??0)+1;$table_counts[$table]=($table_counts[$table]??0)+1;}return['summary'=>['total_issues'=>$total_issues,'severity_breakdown'=>$severity_counts,'type_breakdown'=>$type_counts,'table_breakdown'=>$table_counts,'status'=>$total_issues===0?'healthy':($severity_counts['high']>0?'critical':'warning')],'issues'=>$this->issues,'recommendations'=>$this->generateRecommendations(),'timestamp'=>date('c')];}/***Generaterecommendationsbasedonissuesfound*/privatefunctiongenerateRecommendations(){$recommendations=[];$high_issues=array_filter($this->issues,function($i){return$i['severity']==='high';});$medium_issues=array_filter($this->issues,function($i){return$i['severity']==='medium';});if(!empty($high_issues)){$recommendations[]='Addresshighseverityissuesfirstastheymayaffectapplicationfunctionality';}$missing_fields=array_filter($this->issues,function($i){return$i['type']==='missing_required_fields';});if(!empty($missing_fields)){$recommendations[]='Updaterecordswithmissingrequiredfieldstoensuredatacompleteness';}$invalid_refs=array_filter($this->issues,function($i){returnstrpos($i['type'],'invalid_')===0;});if(!empty($invalid_refs)){$recommendations[]='Fixinvalidforeignkeyreferencestomaintaindataintegrity';}$duplicates=array_filter($this->issues,function($i){returnstrpos($i['type'],'duplicate_')===0;});if(!empty($duplicates)){$recommendations[]='Resolveduplicaterecordstoensuredatauniqueness';}if(!empty($medium_issues)){$recommendations[]='Reviewmediumseverityissuesfordataqualityimprovements';}return$recommendations;}}/Runvalidationifaccesseddirectlyif(basename($_SERVER['PHP_SELF'])===basename(__FILE__)){header('Content-Type:application/json');try{$validator=newDataIntegrityValidator();$result=$validator->validateAll();echojson_encode(['success'=>true,'data'=>$result,'timestamp'=>date('c')]);}catch(Exception$e){echojson_encode(['success'=>false,'message'=>$e->getMessage(),'timestamp'=>date('c')]);}}?>
